// Amostra mínima: separação clara entre texto e código.
function renderSection(title, items) {
  return {
    title,
    bullets: items.map((x) => String(x).trim()),
  };
}

const section = renderSection('Critérios', ['Metadados', 'Determinismo', 'Legibilidade']);
console.log(section);
